css:
.ps-home-grid__row { display: grid; grid-template-columns: repeat(3, 1fr); gap: var(--pds-space-2); margin-block-end: var(--pds-space-4); }
@media (max-width: 959px) { .ps-home-grid__row { grid-template-columns: repeat(2, 1fr); } }
@media (max-width: 639px) { .ps-home-grid__row { grid-template-columns: 1fr; } }
.ps-home-grid__card { border: 1px solid var(--pds-border-subtle); border-radius: var(--pds-radius-xs); padding: var(--pds-space-2); background: var(--pds-surface-layer); transition: border-color var(--pds-duration-fast) ease; }
.ps-home-grid__card:hover { border-color: var(--pds-link); }
@media (prefers-reduced-motion: reduce) { .ps-home-grid__card { transition: none; } }
.ps-home-grid__heading { font-size: 1.125rem; font-weight: 600; margin-block-end: var(--pds-space-2); }
.ps-home-grid__title { font-size: 1.0625rem; font-weight: 600; margin-block-end: 0.25rem; }
.ps-home-grid__title a { color: var(--pds-link); text-decoration: none; }
.ps-home-grid__title a:hover { text-decoration: underline; }
.ps-home-grid__title a:focus-visible { outline: 2px solid var(--pds-focus-ring); outline-offset: 2px; }
.ps-home-grid__count, .ps-home-grid__empty { font-size: 0.8125rem; color: var(--pds-text-secondary); margin-block-end: 0.5rem; }
.ps-home-grid__list { list-style: none; padding: 0; margin-block-end: 0.5rem; font-size: 0.875rem; }
.ps-home-grid__list li { padding-block: 0.125rem; }
.ps-home-grid__list a { color: var(--pds-link); }
.ps-home-grid__more { font-size: 0.8125rem; color: var(--pds-link); }
